const functions = require('@google-cloud/functions-framework');
const { BigQuery } = require('@google-cloud/bigquery');

const bigquery = new BigQuery();

async function processLargeDataset(req, res) {
  const projectId =
    process.env.BIGQUERY_PROJECT_ID ||
    process.env.GOOGLE_CLOUD_PROJECT ||
    process.env.GCLOUD_PROJECT;

  const datasetId = process.env.BIGQUERY_DATASET || 'your_dataset';
  const tableId = process.env.BIGQUERY_TABLE || 'your_table';

  const query = `
    SELECT
      *
    FROM \`${projectId}.${datasetId}.${tableId}\`
  `;

  try {
    const [job] = await bigquery.createQueryJob({
      query,
      location: process.env.BIGQUERY_LOCATION || 'US',
      useLegacySql: false,
    });

    const rows = [];
    let pageToken;

    do {
      const [results, nextQuery, response] = await job.getQueryResults({
        pageToken,
        maxResults: 100000,
      });

      rows.push(...results);
      pageToken = response.pageToken;
    } while (pageToken);

    const aggregated = rows.reduce(
      (acc, row) => {
        acc.totalRows += 1;

        for (const [key, value] of Object.entries(row)) {
          if (typeof value === 'number') {
            acc.numericSums[key] = (acc.numericSums[key] || 0) + value;
          } else if (value !== null && value !== undefined) {
            acc.nonNullCounts[key] = (acc.nonNullCounts[key] || 0) + 1;
          }
        }

        return acc;
      },
      {
        totalRows: 0,
        numericSums: {},
        nonNullCounts: {},
      }
    );

    res.status(200).json({
      success: true,
      config: {
        requestedMemory: '8GiB',
        requestedTimeoutSeconds: 540,
      },
      jobId: job.id,
      aggregated,
    });
  } catch (error) {
    console.error('BigQuery processing failed:', error);
    res.status(500).json({
      success: false,
      error: error.message,
    });
  }
}

functions.http('processLargeDataset', processLargeDataset);

